167: class DrainingFilterChainsManager {
168: public:
169:   DrainingFilterChainsManager(ListenerImplPtr&& draining_listener,
170:                               uint64_t workers_pending_removal);
171:   uint64_t getDrainingListenerTag() const { return draining_listener_->listenerTag(); }
172:   const std::list<const Network::FilterChain*>& getDrainingFilterChains() const {
173:     return draining_filter_chains_;
174:   }
175:   ListenerImpl& getDrainingListener() const { return *draining_listener_; }
176:   uint64_t decWorkersPendingRemoval() { return --workers_pending_removal_; }
177: 
178:   // Schedule listener destroy.
179:   void startDrainSequence(std::chrono::seconds drain_time, Event::Dispatcher& dispatcher,
180:                           std::function<void()> completion) {
181:     drain_sequence_completion_ = completion;
182:     ASSERT(!drain_timer_);
183: 
184:     drain_timer_ = dispatcher.createTimer([this]() -> void { drain_sequence_completion_(); });
185:     drain_timer_->enableTimer(drain_time);
186:   }
187: 
188:   void addFilterChainToDrain(const Network::FilterChain& filter_chain) {
189:     draining_filter_chains_.push_back(&filter_chain);
190:   }
191: 
192:   uint32_t numDrainingFilterChains() const { return draining_filter_chains_.size(); }
193: 
194: private:
195:   ListenerImplPtr draining_listener_;
196:   std::list<const Network::FilterChain*> draining_filter_chains_;
197: 
198:   uint64_t workers_pending_removal_;
199:   Event::TimerPtr drain_timer_;
200:   std::function<void()> drain_sequence_completion_;
201: };
